public static List<Integer> fibonacci(int n) {
    List<Integer> result = new ArrayList<>();
    int a = 0, b = 1;
    for (int i = 0; i < n; i++) {
        result.add(a);
        int next = a + b;
        a = b;
        b = next;
    }
    return result;
}

